-- ================================================================
-- MAKNANAME — Complete PostgreSQL Database
-- Host gratis: supabase.com | neon.tech | railway.app
-- ================================================================

-- ================================================================
-- SCHEMA TABLES
-- ================================================================

CREATE TABLE IF NOT EXISTS nama_dasar (
  id              SERIAL PRIMARY KEY,
  nama            VARCHAR(120) UNIQUE NOT NULL,
  asal_bahasa     VARCHAR(60),
  kode_bahasa     CHAR(5),
  makna_singkat   VARCHAR(400),
  makna_detail    TEXT,
  arti_arab       VARCHAR(300),
  transliterasi   VARCHAR(150),
  gender          CHAR(1) DEFAULT 'N',   -- L / P / N
  kategori        VARCHAR(60),
  agama           VARCHAR(40) DEFAULT 'Universal',
  suku            VARCHAR(40),
  sifat_positif   TEXT[],
  sifat_perhatian TEXT[],
  numerologi      INT,
  popularitas     INT DEFAULT 0,
  sumber          VARCHAR(20) DEFAULT 'manual',
  terverifikasi   BOOLEAN DEFAULT TRUE,
  dibuat_pada     TIMESTAMPTZ DEFAULT NOW(),
  diperbarui_pada TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS cache_analisis (
  id              SERIAL PRIMARY KEY,
  nama_lengkap    VARCHAR(400) UNIQUE NOT NULL,
  nama_hash       VARCHAR(64) UNIQUE NOT NULL,
  hasil_json      JSONB NOT NULL,
  jumlah_akses    INT DEFAULT 1,
  sumber          VARCHAR(20) DEFAULT 'ai',
  dibuat_pada     TIMESTAMPTZ DEFAULT NOW(),
  terakhir_akses  TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS log_pencarian (
  id           SERIAL PRIMARY KEY,
  nama_dicari  VARCHAR(400),
  durasi_ms    INT,
  sumber       VARCHAR(20),
  waktu        TIMESTAMPTZ DEFAULT NOW()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_nama_lower     ON nama_dasar(LOWER(nama));
CREATE INDEX IF NOT EXISTS idx_nama_kategori  ON nama_dasar(kategori);
CREATE INDEX IF NOT EXISTS idx_nama_gender    ON nama_dasar(gender);
CREATE INDEX IF NOT EXISTS idx_popularitas    ON nama_dasar(popularitas DESC);
CREATE INDEX IF NOT EXISTS idx_cache_hash     ON cache_analisis(nama_hash);
CREATE INDEX IF NOT EXISTS idx_cache_akses    ON cache_analisis(terakhir_akses DESC);

-- Auto-update timestamp trigger
CREATE OR REPLACE FUNCTION fn_update_timestamp()
RETURNS TRIGGER AS $$
BEGIN NEW.diperbarui_pada = NOW(); RETURN NEW; END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_nama_timestamp ON nama_dasar;
CREATE TRIGGER trg_nama_timestamp
  BEFORE UPDATE ON nama_dasar
  FOR EACH ROW EXECUTE FUNCTION fn_update_timestamp();

-- ================================================================
-- VIEWS
-- ================================================================

CREATE OR REPLACE VIEW v_statistik AS
SELECT
  COUNT(*)                                          AS total_nama,
  COUNT(DISTINCT asal_bahasa)                       AS jumlah_bahasa,
  SUM(CASE WHEN gender='L' THEN 1 ELSE 0 END)      AS nama_laki,
  SUM(CASE WHEN gender='P' THEN 1 ELSE 0 END)      AS nama_perempuan,
  SUM(CASE WHEN gender='N' THEN 1 ELSE 0 END)      AS nama_netral,
  SUM(CASE WHEN terverifikasi THEN 1 ELSE 0 END)   AS terverifikasi,
  SUM(CASE WHEN sumber='ai' THEN 1 ELSE 0 END)     AS dari_ai
FROM nama_dasar;

CREATE OR REPLACE VIEW v_cache_stats AS
SELECT
  COUNT(*)          AS total_cache,
  SUM(jumlah_akses) AS total_akses,
  MAX(terakhir_akses) AS terakhir_pencarian
FROM cache_analisis;

